+fn rapid_restart_churn_keeps_event_sequence_balanced() {
+    let mut dispatcher = WasmExportDispatcher::new();
+    let (runtime, scope) = dispatcher
+        .create_scoped_runtime(Some("react-restart-churn"), None)
