+            None,
+        )
+        .expect("initial task spawn should succeed");
+
+    for attempt in 1..=restart_count {
+        dispatcher
+            .task_cancel(
+                &WasmTaskCancelRequest {
+                    task: current,
+                    kind: "render_churn".to_string(),
+                    message: Some(format!("restart-churn-{attempt}")),
